INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES ("2020/04/30 12:00:00", 24001, 0, 10040, 1, 0.0, "2030/12/17 14:59:59", 0.0, 24, "リン", 1, 0.0, "あたしだって\nやるときはやるよ！", 102601);
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES ("2020/04/30 12:00:00", 24002, 1, 10040, 1, 0.0, "2030/12/17 14:59:59", 0.0, 24, "リン", 1, 0.0, "ふぅ…\nこれであたしの仕事は\n終わりだね", 102601);
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES ("2020/04/30 12:00:00", 24003, 2, 10040, 1, 0.0, "2030/12/17 14:59:59", 0.0, 24, "リン", 1, 0.0, "終わった終わった\n一人でもなんとか\nなるもんだね", 102601);
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES ("2020/04/30 12:00:00", 24004, 3, 10040, 2, 0.0, "2030/12/17 14:59:59", 0.0, 24, "リン", 2, 0.0, "やったね！\nこれでようやく\nサボれるよ…", 102601);
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES ("2020/04/30 12:00:00", 24005, 4, 10040, 1, 0.0, "2030/12/17 14:59:59", 0.0, 24, "リン", 1, 0.0, "チーズが欲しいなら\nきちんと働いて\n買いに来なよ", 102601);
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES ("2020/04/30 12:00:00", 24006, 5, 10040, 2, 0.0, "2030/12/17 14:59:59", 0.0, 24, "リン", 2, 0.0, "あたしを敵に回した\n恐ろしさ\n思い知ったか！", 102601);
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES ("2020/04/30 12:00:00", 24007, 6, 10040, 2, 0.0, "2030/12/17 14:59:59", 0.0, 24, "リン", 2, 0.0, "あたしも意外と\nやるもんでしょ？", 102601);
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES ("2020/04/30 12:00:00", 24008, 7, 10040, 4, 0.0, "2030/12/17 14:59:59", 0.0, 24, "リン", 4, 0.0, "疲れた…\nねずみの逃げ足\n速すぎるよ…", 102601);
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES ("2020/04/30 12:00:00", 24009, 8, 10040, 4, 0.0, "2030/12/17 14:59:59", 0.0, 24, "リン", 4, 0.0, "このままじゃ\nまっひ～に\n叱られちゃうよ", 102601);
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES ("2020/04/30 12:00:00", 24010, 9, 10040, 4, 0.0, "2030/12/17 14:59:59", 0.0, 24, "リン", 4, 0.0, "まじめに\nやったんだけどな…\n悔しいな～", 102601);
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES ("2020/04/30 12:00:00", 24011, 10, 10040, 4, 0.0, "2030/12/17 14:59:59", 0.0, 24, "リン", 4, 0.0, "やられた…\nねずみって意外と\nてごわいね", 102601);
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES ("2020/04/30 12:00:00", 24012, 11, 10040, 4, 0.0, "2030/12/17 14:59:59", 0.0, 24, "リン", 4, 0.0, "おのれ～\nあたしのチーズを\n盗みやがって～！", 102601);
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES ("2020/04/30 12:00:00", 24013, 12, 10040, 4, 0.0, "2030/12/17 14:59:59", 0.0, 24, "リン", 1, 1.81, "疲れた…\nけど、次こそは\n守り抜くよ…", 102601);
